+func timelineInfoShouldReplace(existing, candidate TimelineInfo) bool {
+	if !candidate.Compressed && existing.Compressed {
+		return true
+	}
+	if candidate.Compressed && !existing.Compressed {
+		return false
+	}
+	if candidate.ModifiedAt.After(existing.ModifiedAt) {
+		return true
+	}
+	return false
+}
